import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void realisticAmounts() {
        // typical banking scenario with varied transaction amounts in cents
        assertArrayEquals(
            new int[]{99, 150, 199, 250, 300, 400, 500, 1000},
            new Solution().mergeBatches(
                new int[][]{{99, 199, 500},{250, 300},{150, 400, 1000}})
        );
    }

    @Test
    void singleBatch() {
        // k=1: one day's batch returned unchanged
        assertArrayEquals(
            new int[]{100, 200, 300},
            new Solution().mergeBatches(new int[][]{{100, 200, 300}})
        );
    }

    @Test
    void emptyBatchAmongOthers() {
        // one day had zero transactions — must not crash
        assertArrayEquals(
            new int[]{50, 75, 120, 300},
            new Solution().mergeBatches(new int[][]{{50, 120},{},{75, 300}})
        );
    }

    @Test
    void emptyInput() {
        // no batches at all
        assertArrayEquals(
            new int[]{},
            new Solution().mergeBatches(new int[][]{})
        );
    }

    @Test
    void twoBatchesSameAmounts() {
        // duplicate amounts across batches; lower batch index appears first
        // batch0 has 500, batch1 has 500 -> [500, 500, 750]
        assertArrayEquals(
            new int[]{500, 500, 750},
            new Solution().mergeBatches(new int[][]{{500},{500, 750}})
        );
    }

    @Test
    void largeMixedBatches() {
        // five single-element batches of varying amounts
        assertArrayEquals(
            new int[]{10, 20, 30, 40, 50},
            new Solution().mergeBatches(new int[][]{{30},{10},{50},{20},{40}})
        );
    }

    @Test
    void allBatchesEmpty() {
        // multiple batches, all empty
        assertArrayEquals(
            new int[]{},
            new Solution().mergeBatches(new int[][]{{},{},{}})
        );
    }
}
